func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path
		query := c.Request.URL.RawQuery

		c.Next()

		latency := time.Since(start)
		status := c.Writer.Status()
		method := c.Request.Method

		klog.Infof("[%s] %s %s?%s - Status: %d - Latency: %v",
			method, path, query, status, latency)
	}
}

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"message": "Missing authorization header"})
			c.Abort()
			return
		}

		parts := strings.Split(authHeader, " ")
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.JSON(http.StatusUnauthorized, gin.H{"message": "Invalid authorization header format"})
			c.Abort()
			return
		}

		token := parts[1]

		cacheKey := token
		if _, found := s.tokenCache.Get(cacheKey); found {
			c.Set("userToken", token)
			c.Next()
			return
		}

		tr := &authenticationv1.TokenReview{
			Spec: authenticationv1.TokenReviewSpec{
				Token: token,
			},
		}

		result, err := s.k8sClient.clientset.AuthenticationV1().TokenReviews().Create(c.Request.Context(), tr, metav1.CreateOptions{})
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"message": "Failed to validate token"})
			c.Abort()
			return
		}

		if !result.Status.Authenticated {
			c.JSON(http.StatusUnauthorized, gin.H{"message": "Invalid token"})
			c.Abort()
			return
		}

		s.tokenCache.Put(cacheKey, token)

		username := result.Status.User.Username
		c.Set("userToken", token)
		c.Set("username", username)

		if strings.HasPrefix(username, "system:serviceaccount:") {
			parts := strings.Split(username, ":")
			if len(parts) >= 4 {
				c.Set("serviceAccount", parts[3])
