func TestServer_concurrencyLimitMiddleware(t *testing.T) {
	os.Setenv("WORKLOAD_MANAGER_URL", "http://localhost:8080")
	defer os.Unsetenv("WORKLOAD_MANAGER_URL")

	cfg := &Config{
		Port:                  "8080",
		MaxConcurrentRequests: 2,
	}

	server, err := NewServer(cfg, &mockSessionManager{})
	require.NoError(t, err)

	middleware := server.concurrencyLimitMiddleware()

	engine := gin.New()
	engine.Use(middleware)

	visited := 0
	var mu sync.Mutex
	engine.GET("/test", func(c *gin.Context) {
		mu.Lock()
		visited++
		mu.Unlock()
		time.Sleep(100 * time.Millisecond)
		c.JSON(http.StatusOK, gin.H{"ok": true})
	})

	done := make(chan bool, 5)
	for i := 0; i < 5; i++ {
		go func() {
			req := httptest.NewRequest("GET", "/test", nil)
			w := httptest.NewRecorder()
			engine.ServeHTTP(w, req)
			done <- true
		}()
	}

	for i := 0; i < 5; i++ {
		<-done
	}

	if visited != 5 {
		t.Errorf("expected 5 visited, got: %d", visited)
	}
}

func TestServer_concurrencyLimitMiddleware_Exceeded(t *testing.T) {
	os.Setenv("WORKLOAD_MANAGER_URL", "http://localhost:8080")
	defer os.Unsetenv("WORKLOAD_MANAGER_URL")

	cfg := &Config{
		Port:                  "8080",
		MaxConcurrentRequests: 1,
	}

	server, err := NewServer(cfg, &mockSessionManager{})
	require.NoError(t, err)

	middleware := server.concurrencyLimitMiddleware()

	engine := gin.New()
	engine.Use(middleware)
	engine.GET("/test", func(c *gin.Context) {
		time.Sleep(500 * time.Millisecond)
		c.JSON(http.StatusOK, gin.H{"ok": true})
	})

	var wg sync.WaitGroup
	var overloadCount int32

	for i := 0; i < 5; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			req := httptest.NewRequest("GET", "/test", nil)
			w := httptest.NewRecorder()
			engine.ServeHTTP(w, req)
			if w.Code == http.StatusTooManyRequests {
				atomic.AddInt32(&overloadCount, 1)
			}
		}()
		time.Sleep(10 * time.Millisecond)
	}

	wg.Wait()

	if overloadCount <= 0 {
		t.Error("Some requests should be rate-limited")
	}
}

