		Max:    max,
		Count:  limit,
		Offset: 0,
	}).Result()
	if err != nil {
		return nil, err
	}

	if len(members) == 0 {
		return nil, nil
	}

	return r.loadSandboxesBySessionIDs(ctx, members)
}

func (r *redisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = r.sessionKey(id)
	}

	results, err := r.cli.MGet(ctx, keys...).Result()
	if err != nil {
