package store

import (
	"context"
	"encoding/json"
	"fmt"
	"strconv"
	"time"

	redisv9 "github.com/redis/go-redis/v9"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"k8s.io/klog/v2"
)

type redisStore struct {
	cli                  *redisv9.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func newRedisStore() *redisStore {
	addr := getEnv("REDIS_ADDR", "")
	if addr == "" {
		klog.Fatalf("REDIS_ADDR is required")
	}

	password := getEnv("REDIS_PASSWORD", "")
	passwordRequired := getEnv("REDIS_PASSWORD_REQUIRED", "true")
	if passwordRequired != "false" && password == "" {
		klog.Fatalf("REDIS_PASSWORD is required")
	}

	options := &redisv9.Options{
		Addr:     addr,
		Password: password,
	}

	return &redisStore{
		cli:                  redisv9.NewClient(options),
		sessionPrefix:        "session:",
		expiryIndexKey:       "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}
}

func (r *redisStore) Ping(ctx context.Context) error {
	result, err := r.cli.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping result: %s", result)
	}
	return nil
}

func (r *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := r.sessionKey(sessionID)
	data, err := r.cli.Get(ctx, key).Result()
	if err == redisv9.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (r *redisStore) StoreSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	if sandboxStore == nil {
		return fmt.Errorf("sandbox is nil")
	}
	if sandboxStore.ExpiresAt.IsZero() {
		return fmt.Errorf("expiresAt is required")
	}

	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}

	key := r.sessionKey(sandboxStore.SessionID)
	pipe := r.cli.Pipeline()

	pipe.SetNX(ctx, key, data, 0)
	pipe.ZAdd(ctx, r.expiryIndexKey, redisv9.Z{
		Score:  float64(sandboxStore.ExpiresAt.Unix()),
		Member: sandboxStore.SessionID,
	})
	pipe.ZAdd(ctx, r.lastActivityIndexKey, redisv9.Z{
		Score:  float64(time.Now().Unix()),
		Member: sandboxStore.SessionID,
	})

	_, err = pipe.Exec(ctx)
	return err
}

func (r *redisStore) UpdateSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	if sandboxStore == nil {
		return fmt.Errorf("sandbox is nil")
	}

	key := r.sessionKey(sandboxStore.SessionID)
	exists, err := r.cli.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}

	_, err = r.cli.Set(ctx, key, data, 0).Result()
	return err
}

func (r *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := r.sessionKey(sessionID)
	pipe := r.cli.Pipeline()

	pipe.Del(ctx, key)
	pipe.ZRem(ctx, r.expiryIndexKey, sessionID)
	pipe.ZRem(ctx, r.lastActivityIndexKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (r *redisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return r.listSandboxesByZSET(ctx, r.expiryIndexKey, "-inf", strconv.FormatInt(before.Unix(), 10), limit)
}

func (r *redisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return r.listSandboxesByZSET(ctx, r.lastActivityIndexKey, "-inf", strconv.FormatInt(before.Unix(), 10), limit)
}

func (r *redisStore) listSandboxesByZSET(ctx context.Context, zsetKey, min, max string, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

