}

func TestManager_GetSandboxBySession_ExistingSession(t *testing.T) {
	mr := setupTestRedis(t)
	client := redisv9.NewClient(&redisv9.Options{
		Addr: mr.Addr(),
	})
	client.Ping(context.Background())

	ctx := context.Background()

	sandbox := &types.SandboxInfo{
		SessionID:        "existing-session",
		SandboxID:        "sandbox-123",
		SandboxNamespace: "default",
		Name:             "test",
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(1 * time.Hour),
		Status:           "running",
	}

	data, err := json.Marshal(sandbox)
	require.NoError(t, err)
	client.Set(ctx, "session:existing-session", data, 0)

	sm, err := NewSessionManager(nil)
	require.NoError(t, err)

	result, err := sm.GetSandboxBySession(ctx, "existing-session", "default", "test", types.AgentRuntimeKind)
	require.NoError(t, err)
	assert.Equal(t, sandbox.SessionID, result.SessionID)
}

