	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		resp := map[string]interface{}{
			"sessionId":   "new-session-id",
			"sandboxId":   "new-sandbox",
			"sandboxNs":   "default",
			"kind":        "AgentRuntime",
			"name":        "test",
			"status":      "running",
			"entryPoints": []types.SandboxEntryPoint{
				{
					Path:     "/",
					Protocol: "http",
