	ctx := context.Background()
	sm := &manager{
		workloadMgrAddr: server.URL,
		httpClient:      &http.Client{Timeout: 2 * time.Minute},
	}

	sandbox, err := sm.createSandbox(ctx, "default", "test", types.AgentRuntimeKind)
